import React, { useState, useEffect, useCallback, useRef } from 'react';
import usePageTitle from '../hooks/usePageTitle';
import { api, apiPost } from '../utils/api';
import { tokens } from '../styles/tokens';
import s from './PolicySimulatorPage.module.css';

/* -- Design tokens (kept for dynamic color logic only) -------------------- */
const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
};

/* -- Panel ----------------------------------------------------------------- */
function Panel({ children, className, style }) {
  return (
    <div className={className || s.panel} style={style}>
      {children}
    </div>
  );
}

/* -- Badge ----------------------------------------------------------------- */
function Badge({ label, color }) {
  return (
    <span
      className={s.badge}
      style={{
        color: color || C.textSecondary,
        background: `${color || C.textSecondary}15`,
        border: `1px solid ${color || C.textSecondary}25`,
      }}
    >
      {label}
    </span>
  );
}

/* -- Styled Select --------------------------------------------------------- */
function StyledSelect({ value, onChange, options, placeholder, style: extraStyle }) {
  return (
    <select
      value={value}
      onChange={e => onChange(e.target.value)}
      className={s.styledSelect}
      style={extraStyle}
    >
      {placeholder && <option value="">{placeholder}</option>}
      {options.map(opt => (
        <option key={typeof opt === 'string' ? opt : opt.value} value={typeof opt === 'string' ? opt : opt.value}>
          {typeof opt === 'string' ? opt : opt.label}
        </option>
      ))}
    </select>
  );
}

/* -- Styled Input ---------------------------------------------------------- */
function StyledInput({ value, onChange, placeholder, style: extraStyle, ...props }) {
  return (
    <input
      type="text"
      value={value}
      onChange={e => onChange(e.target.value)}
      placeholder={placeholder}
      className={s.styledInput}
      style={extraStyle}
      {...props}
    />
  );
}

/* -- Styled Button --------------------------------------------------------- */
function StyledButton({ children, onClick, color, disabled, style: extraStyle }) {
  const c = color || C.blue;
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={s.styledButton}
      style={{
        border: `1px solid ${c}40`,
        background: `${c}15`,
        color: c,
        opacity: disabled ? 0.4 : 1,
        ...extraStyle,
      }}
    >
      {children}
    </button>
  );
}

/* -- Countdown Timer ------------------------------------------------------- */
function CountdownTimer({ expiresAt }) {
  const [remaining, setRemaining] = useState('');

  useEffect(() => {
    const update = () => {
      const now = Date.now();
      const target = typeof expiresAt === 'number' && expiresAt < 1e12
        ? expiresAt * 1000
        : new Date(expiresAt).getTime();
      const diff = target - now;
      if (diff <= 0) {
        setRemaining('EXPIRED');
        return;
      }
      const mins = Math.floor(diff / 60000);
      const secs = Math.floor((diff % 60000) / 1000);
      setRemaining(`${mins}m ${secs}s`);
    };
    update();
    const iv = setInterval(update, 1000);
    return () => clearInterval(iv);
  }, [expiresAt]);

  return (
    <span className={s.bgCountdown}>
      {remaining}
    </span>
  );
}

/* -- Common runbooks list -------------------------------------------------- */
const COMMON_RUNBOOKS = [
  'restart_service_once',
  'rollback_release',
  'enforce_trading_disarm',
  'deploy_release',
  'toggle_feature_flag',
  'rotate_credentials',
  'scale_service',
  'clear_cache',
  'run_migration',
  'update_config',
];

const ENVIRONMENTS = ['staging', 'prod-canary', 'prod'];

/* -- Break-Glass Modal ----------------------------------------------------- */
function BreakGlassModal({ onClose, onActivate }) {
  const [justification, setJustification] = useState('');
  const [phrase, setPhrase] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const canActivate = phrase === 'BREAKGLASS' && justification.trim().length > 0;

  const handleActivate = async () => {
    if (!canActivate) return;
    setSubmitting(true);
    await onActivate(justification, phrase);
    setSubmitting(false);
    onClose();
  };

  return (
    <div
      onClick={onClose}
      className={s.bgModalOverlay}
    >
      <div
        onClick={e => e.stopPropagation()}
        className={s.bgModalContent}
      >
        <h3 className={s.bgModalTitle}>
          Activate Break-Glass Override
        </h3>
        <p className={s.bgModalDesc}>
          This bypasses all approval gates. Actions taken during break-glass are fully audited.
        </p>

        <div className={s.bgModalField}>
          <label className={s.bgModalLabel}>
            Justification (required)
          </label>
          <textarea
            value={justification}
            onChange={e => setJustification(e.target.value)}
            placeholder="Describe why break-glass access is needed..."
            rows={3}
            className={s.bgModalTextarea}
          />
        </div>

        <div className={s.bgModalFieldLarge}>
          <label className={s.bgModalLabel}>
            Type <span className={s.bgModalConfirmText}>BREAKGLASS</span> to confirm
          </label>
          <StyledInput
            value={phrase}
            onChange={setPhrase}
            placeholder="BREAKGLASS"
            style={{
              borderColor: phrase === 'BREAKGLASS' ? C.red : C.border,
            }}
          />
        </div>

        <div className={s.bgModalFooter}>
          <StyledButton onClick={onClose} color={C.textSecondary}>
            Cancel
          </StyledButton>
          <StyledButton
            onClick={handleActivate}
            color={C.red}
            disabled={!canActivate || submitting}
          >
            {submitting ? 'Activating...' : 'Activate Break-Glass'}
          </StyledButton>
        </div>
      </div>
    </div>
  );
}

/* =========================================================================
   POLICY SIMULATOR PAGE
   ========================================================================= */
export default function PolicySimulatorPage() {
  usePageTitle('Policy Simulator');

  // -- State: intent builder --
  const [runbook, setRunbook] = useState('');
  const [environment, setEnvironment] = useState('');
  const [contextEntries, setContextEntries] = useState([{ key: '', value: '' }]);

  // -- State: simulation result --
  const [simResult, setSimResult] = useState(null);
  const [simulating, setSimulating] = useState(false);
  const [simError, setSimError] = useState(null);

  // -- State: break-glass --
  const [breakGlassState, setBreakGlassState] = useState(null);
  const [bgLoading, setBgLoading] = useState(true);
  const [bgModalOpen, setBgModalOpen] = useState(false);
  const [bgDeactivating, setBgDeactivating] = useState(false);

  // -- State: policy summary --
  const [policySummary, setPolicySummary] = useState(null);

  // -- State: examples drawer --
  const [examples, setExamples] = useState([]);
  const [examplesOpen, setExamplesOpen] = useState(false);
  const [examplesLoading, setExamplesLoading] = useState(false);

  // -- State: page-level --
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const abortRef = useRef(null);

  // -- Fetch break-glass state + policy summary --
  const fetchState = useCallback(async () => {
    try {
      const [bgData, policyData] = await Promise.all([
        api('/breakglass/state', { silent: true }),
        api('/policy/summary', { silent: true }),
      ]);
      if (bgData) setBreakGlassState(bgData);
      if (policyData) setPolicySummary(policyData);
      setError(null);
    } catch (e) {
      setError(e.message);
    }
    setBgLoading(false);
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchState();
    const iv = setInterval(fetchState, 15000);
    return () => clearInterval(iv);
  }, [fetchState]);

  // -- Load examples --
  const loadExamples = async () => {
    if (examples.length > 0) {
      setExamplesOpen(o => !o);
      return;
    }
    setExamplesLoading(true);
    setExamplesOpen(true);
    const data = await api('/policy/simulate/examples', { silent: true });
    if (data && Array.isArray(data)) {
      setExamples(data);
    }
    setExamplesLoading(false);
  };

  // -- Context entries management --
  const addContextEntry = () => {
    setContextEntries(prev => [...prev, { key: '', value: '' }]);
  };

  const removeContextEntry = (index) => {
    setContextEntries(prev => prev.filter((_, i) => i !== index));
  };

  const updateContextEntry = (index, field, value) => {
    setContextEntries(prev => prev.map((entry, i) =>
      i === index ? { ...entry, [field]: value } : entry
    ));
  };

  // -- Build context object from entries --
  const buildContext = () => {
    const ctx = {};
    contextEntries.forEach(entry => {
      if (entry.key.trim()) {
        let val = entry.value;
        if (val === 'true') val = true;
        else if (val === 'false') val = false;
        else if (!isNaN(val) && val.trim() !== '') val = Number(val);
        ctx[entry.key.trim()] = val;
      }
    });
    return ctx;
  };

  // -- Simulate --
  const handleSimulate = async () => {
    if (!runbook || !environment) return;
    setSimulating(true);
    setSimError(null);
    setSimResult(null);

    const payload = {
      runbook,
      environment,
      context: buildContext(),
    };

    const result = await apiPost('/policy/simulate', payload);
    if (result) {
      setSimResult(result);
    } else {
      setSimError('Simulation failed. Check that the backend is running and the policy engine is loaded.');
    }
    setSimulating(false);
  };

  // -- Break-glass activate --
  const handleBreakGlassActivate = async (justification, phrase) => {
    const result = await apiPost('/breakglass/request', {
      requested_by: 'admin',
      phrase,
      justification,
    });
    if (result) {
      fetchState();
    }
  };

  // -- Break-glass deactivate --
  const handleBreakGlassDeactivate = async () => {
    setBgDeactivating(true);
    const result = await apiPost('/breakglass/deactivate', {
      deactivated_by: 'admin',
    });
    if (result) {
      fetchState();
    }
    setBgDeactivating(false);
  };

  // -- Auto-fill from example --
  const fillFromExample = (example) => {
    setRunbook(example.runbook || '');
    setEnvironment(example.environment || '');
    const ctx = example.context || {};
    const entries = Object.entries(ctx).map(([key, value]) => ({
      key,
      value: String(value),
    }));
    setContextEntries(entries.length > 0 ? entries : [{ key: '', value: '' }]);
    setSimResult(null);
    setSimError(null);
    setExamplesOpen(false);
  };

  // -- Reload policy --
  const handleReloadPolicy = async () => {
    const result = await apiPost('/policy/reload', {});
    if (result) {
      fetchState();
    }
  };

  const bgActive = breakGlassState?.active === true;
  const bgSession = breakGlassState?.session;

  // -- Evaluation data from simulation --
  const evaluation = simResult?.evaluation || simResult?.simulation_result?.evaluation || null;
  const satisfaction = simResult?.satisfaction_check || simResult?.simulation_result?.satisfaction_check || null;
  const autoApproved = simResult?.auto_approved;

  return (
    <div className={s.page}>
      {/* -- Header --------------------------------------------------------- */}
      <div className={s.header}>
        <div>
          <h1 className={s.headerTitle}>Policy Simulator</h1>
          <p className={s.headerSubtitle}>
            Simulate policy evaluation, test approval gates, and manage break-glass access
          </p>
        </div>
        <div className={s.headerActions}>
          {policySummary && (
            <span className={s.policyVersion}>
              Policy v{policySummary.version || '?'}
            </span>
          )}
          <StyledButton onClick={handleReloadPolicy} color={C.cyan} style={{ padding: '6px 14px', fontSize: 10 }}>
            Reload Policy
          </StyledButton>
        </div>
      </div>

      {error && (
        <div className={s.errorBanner}>
          Failed to load: {typeof error === 'string' ? error : 'An error occurred'}
        </div>
      )}

      {/* -- Break-Glass Status Banner -------------------------------------- */}
      <Panel
        className={bgActive ? s.panelBgActive : s.panel}
        style={{
          marginBottom: 20,
          borderColor: bgActive ? C.red : undefined,
          ...(bgActive ? { boxShadow: `0 0 20px ${C.red}10` } : {}),
        }}
      >
        <div className={s.bgBannerRow}>
          <div className={s.bgBannerLeft}>
            <div className={bgActive ? s.bgDotActive : s.bgDotInactive} />
            <div>
              <div className={bgActive ? s.bgStatusActive : s.bgStatusInactive}>
                Break-Glass: {bgActive ? 'ACTIVE' : 'Inactive'}
              </div>
              {bgActive && bgSession && (
                <div className={s.bgSessionMeta}>
                  Activated by: {bgSession.requested_by || bgSession.activated_by || 'unknown'}
                  {bgSession.justification && ` | ${bgSession.justification}`}
                </div>
              )}
            </div>
          </div>
          <div className={s.bgBannerRight}>
            {bgActive && bgSession?.expires_at && (
              <div className={s.bgTimerWrap}>
                <div className={s.bgTimerLabel}>Time Remaining</div>
                <CountdownTimer expiresAt={bgSession.expires_at} />
              </div>
            )}
            {bgActive ? (
              <StyledButton
                onClick={handleBreakGlassDeactivate}
                color={C.red}
                disabled={bgDeactivating}
                style={{ padding: '6px 16px', fontSize: 11 }}
              >
                {bgDeactivating ? 'Deactivating...' : 'Deactivate'}
              </StyledButton>
            ) : (
              <StyledButton
                onClick={() => setBgModalOpen(true)}
                color={C.red}
                style={{ padding: '6px 16px', fontSize: 11 }}
              >
                Activate Break-Glass
              </StyledButton>
            )}
          </div>
        </div>
        {bgActive && bgSession?.capabilities && (
          <div className={s.bgCapabilities}>
            <div className={s.bgCapLabel}>Granted Capabilities</div>
            <div className={s.bgCapList}>
              {(Array.isArray(bgSession.capabilities) ? bgSession.capabilities : []).map((cap, i) => (
                <Badge key={i} label={cap} color={C.red} />
              ))}
            </div>
          </div>
        )}
      </Panel>

      {/* -- Main 2-column Layout ------------------------------------------- */}
      <div className={s.twoColumn}>

        {/* ---- Left Panel: Intent Builder --------------------------------- */}
        <div className={s.leftColumn}>
          <Panel>
            <div className={s.sectionHeader}>Intent Builder</div>

            {/* Runbook */}
            <div className={s.formField}>
              <label className={s.formLabel}>Runbook</label>
              <StyledSelect
                value={runbook}
                onChange={setRunbook}
                options={COMMON_RUNBOOKS}
                placeholder="-- Select runbook --"
              />
            </div>

            {/* Environment */}
            <div className={s.formField}>
              <label className={s.formLabel}>Environment</label>
              <StyledSelect
                value={environment}
                onChange={setEnvironment}
                options={ENVIRONMENTS}
                placeholder="-- Select environment --"
              />
            </div>

            {/* Context Key-Value Pairs */}
            <div className={s.formField}>
              <div className={s.contextHeader}>
                <label className={s.formLabel} style={{ marginBottom: 0 }}>
                  Context (key-value pairs)
                </label>
                <button onClick={addContextEntry} className={s.addContextBtn}>
                  + Add
                </button>
              </div>
              <div className={s.contextEntries}>
                {contextEntries.map((entry, i) => (
                  <div key={i} className={s.contextRow}>
                    <StyledInput
                      value={entry.key}
                      onChange={v => updateContextEntry(i, 'key', v)}
                      placeholder="key"
                      style={{ flex: '1 1 40%' }}
                    />
                    <StyledInput
                      value={entry.value}
                      onChange={v => updateContextEntry(i, 'value', v)}
                      placeholder="value"
                      style={{ flex: '1 1 50%' }}
                    />
                    <button
                      onClick={() => removeContextEntry(i)}
                      disabled={contextEntries.length <= 1}
                      className={s.removeContextBtn}
                    >
                      x
                    </button>
                  </div>
                ))}
              </div>
            </div>

            {/* Actions row */}
            <div className={s.actionsRow}>
              <StyledButton
                onClick={handleSimulate}
                color={C.green}
                disabled={!runbook || !environment || simulating}
                style={{ padding: '10px 28px', fontSize: 13, fontWeight: 700 }}
              >
                {simulating ? 'Simulating...' : 'Simulate'}
              </StyledButton>
              <StyledButton
                onClick={loadExamples}
                color={C.purple}
                style={{ padding: '10px 20px', fontSize: 13 }}
              >
                {examplesOpen ? 'Hide Examples' : 'Show Examples'}
              </StyledButton>
            </div>

            {simError && (
              <div className={s.simError}>{simError}</div>
            )}
          </Panel>

          {/* -- Examples Drawer --------------------------------------------- */}
          {examplesOpen && (
            <Panel>
              <div className={s.sectionHeader}>Example Scenarios</div>
              {examplesLoading ? (
                <div className={s.centeredText}>Loading examples...</div>
              ) : examples.length === 0 ? (
                <div className={s.centeredText}>No example scenarios available</div>
              ) : (
                <div className={s.examplesList}>
                  {examples.map((ex, i) => {
                    const exLabel = ex.name || ex.description || `${ex.runbook} / ${ex.environment}`;
                    return (
                      <div
                        key={i}
                        onClick={() => fillFromExample(ex)}
                        className={s.exampleCard}
                      >
                        <div className={s.exampleHeader}>
                          <span className={s.exampleName}>{exLabel}</span>
                          <span className={s.exampleUse}>Use</span>
                        </div>
                        <div className={s.exampleBadges}>
                          <Badge label={ex.runbook || '--'} color={C.cyan} />
                          <Badge label={ex.environment || '--'} color={C.amber} />
                        </div>
                        {ex.expected_outcome && (
                          <div className={s.exampleExpected}>
                            Expected: {typeof ex.expected_outcome === 'string' ? ex.expected_outcome : JSON.stringify(ex.expected_outcome)}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </Panel>
          )}

          {/* -- Policy Summary ---------------------------------------------- */}
          {policySummary && (
            <Panel>
              <div className={s.sectionHeader}>Policy Summary</div>
              <div className={s.policySummaryRow}>
                <div className={s.policySummaryItem}>
                  <div className={s.policySummaryLabel}>Version</div>
                  <div className={s.policySummaryValue} style={{ color: C.blue }}>
                    {policySummary.version || '--'}
                  </div>
                </div>
                <div className={s.policySummaryItem}>
                  <div className={s.policySummaryLabel}>Categories</div>
                  <div className={s.policySummaryValue} style={{ color: C.purple }}>
                    {policySummary.categories ? Object.keys(policySummary.categories).length : 0}
                  </div>
                </div>
              </div>
              {policySummary.categories && (
                <div className={s.categoryList}>
                  {Object.entries(policySummary.categories).map(([catName, catData]) => {
                    const runbookCount = catData.runbooks ? (Array.isArray(catData.runbooks) ? catData.runbooks.length : Object.keys(catData.runbooks).length) : 0;
                    const envs = catData.environments ? Object.keys(catData.environments) : [];
                    return (
                      <div key={catName} className={s.categoryCard}>
                        <div className={s.categoryHeader}>
                          <span className={s.categoryName}>
                            {catName.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}
                          </span>
                          <span className={s.categoryCount}>
                            {runbookCount} runbook{runbookCount !== 1 ? 's' : ''}
                          </span>
                        </div>
                        {envs.length > 0 && (
                          <div className={s.categoryEnvs}>
                            {envs.map(env => (
                              <Badge key={env} label={env} color={C.cyan} />
                            ))}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </Panel>
          )}
        </div>

        {/* ---- Right Panel: Gate Status ----------------------------------- */}
        <div className={s.rightColumn}>
          <Panel>
            <div className={s.sectionHeader}>Gate Status</div>

            {!simResult && !simulating && (
              <div className={s.gateEmpty}>
                Run a simulation to see gate status results here
              </div>
            )}

            {simulating && (
              <div className={s.gateLoading}>
                Evaluating policy...
              </div>
            )}

            {evaluation && (
              <div className={s.gateResults}>
                {/* Auto-approved */}
                {autoApproved !== undefined && (
                  <div
                    className={s.autoApprovedBanner}
                    style={{
                      background: autoApproved ? `${C.green}10` : `${C.amber}10`,
                      border: `1px solid ${autoApproved ? C.green : C.amber}25`,
                    }}
                  >
                    <div className={s.autoApprovedLabel} style={{ color: autoApproved ? C.green : C.amber }}>
                      {autoApproved ? 'AUTO-APPROVED' : 'REQUIRES APPROVAL'}
                    </div>
                  </div>
                )}

                {/* Category */}
                {evaluation.category && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabel}>Category</div>
                    <Badge label={evaluation.category} color={C.purple} />
                  </div>
                )}

                {/* Environment */}
                {evaluation.environment && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabel}>Environment</div>
                    <Badge label={evaluation.environment} color={C.cyan} />
                  </div>
                )}

                {/* Required Approvers */}
                {evaluation.required_approvers !== undefined && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabel}>Required Approvers</div>
                    <div className={s.gateApproverCount}>
                      {evaluation.required_approvers}
                    </div>
                  </div>
                )}

                {/* Required Roles */}
                {evaluation.required_roles && evaluation.required_roles.length > 0 && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabelGap}>Required Roles</div>
                    <div className={s.roleBadges}>
                      {evaluation.required_roles.map((role, i) => (
                        <Badge key={i} label={role} color={C.blue} />
                      ))}
                    </div>
                  </div>
                )}

                {/* Required Inputs */}
                {evaluation.required_inputs && evaluation.required_inputs.length > 0 && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabelGap}>Required Inputs</div>
                    <div className={s.inputList}>
                      {evaluation.required_inputs.map((input, i) => (
                        <div key={i} className={s.inputItem}>
                          {typeof input === 'string' ? input : input.name || JSON.stringify(input)}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Required Artifacts */}
                {evaluation.required_artifacts && evaluation.required_artifacts.length > 0 && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabelGap}>Required Artifacts</div>
                    <div className={s.inputList}>
                      {evaluation.required_artifacts.map((art, i) => (
                        <div key={i} className={s.artifactItem}>
                          {typeof art === 'string' ? art : art.name || JSON.stringify(art)}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Deny Conditions */}
                {evaluation.deny_conditions && evaluation.deny_conditions.length > 0 && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabelGap}>Deny Conditions</div>
                    {evaluation.deny_conditions.map((cond, i) => (
                      <div key={i} className={s.denyCondition}>
                        {typeof cond === 'string' ? cond : cond.description || cond.condition || JSON.stringify(cond)}
                      </div>
                    ))}
                  </div>
                )}

                {/* Reasons */}
                {evaluation.reasons && evaluation.reasons.length > 0 && (
                  <div className={s.gateField}>
                    <div className={s.gateFieldLabelGap}>Reasons</div>
                    <div className={s.reasonsList}>
                      {evaluation.reasons.map((reason, i) => (
                        <div key={i} className={s.reasonItem}>{reason}</div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Policy version */}
                {evaluation.policy_version && (
                  <div className={s.gatePolicyVersion}>
                    Policy version: {evaluation.policy_version}
                  </div>
                )}
              </div>
            )}
          </Panel>

          {/* Satisfaction Check */}
          {satisfaction && (
            <Panel>
              <div className={s.sectionHeader}>Satisfaction Check</div>
              <div className={s.satisfactionRow}>
                <div
                  className={s.satisfactionDot}
                  style={{
                    background: satisfaction.satisfied ? C.green : C.red,
                    boxShadow: `0 0 8px ${satisfaction.satisfied ? C.green : C.red}50`,
                  }}
                />
                <span className={s.satisfactionLabel} style={{ color: satisfaction.satisfied ? C.green : C.red }}>
                  {satisfaction.satisfied ? 'ALL GATES SATISFIED' : 'GATES NOT SATISFIED'}
                </span>
              </div>

              {satisfaction.missing && (
                <div>
                  {satisfaction.missing.approvals !== undefined && satisfaction.missing.approvals > 0 && (
                    <div className={s.missingItem}>
                      Missing {satisfaction.missing.approvals} approval{satisfaction.missing.approvals !== 1 ? 's' : ''}
                    </div>
                  )}
                  {satisfaction.missing.inputs && satisfaction.missing.inputs.length > 0 && (
                    <div className={s.missingItem}>
                      Missing inputs: {satisfaction.missing.inputs.join(', ')}
                    </div>
                  )}
                  {satisfaction.missing.artifacts && satisfaction.missing.artifacts.length > 0 && (
                    <div className={s.missingItem}>
                      Missing artifacts: {satisfaction.missing.artifacts.join(', ')}
                    </div>
                  )}
                  {satisfaction.missing.roles && satisfaction.missing.roles.length > 0 && (
                    <div className={s.missingItem}>
                      Missing roles: {satisfaction.missing.roles.join(', ')}
                    </div>
                  )}
                </div>
              )}
            </Panel>
          )}

          {/* Raw simulation JSON */}
          {simResult && (
            <Panel>
              <div className={s.sectionHeader}>Raw Response</div>
              <pre className={s.rawResponse}>
                {JSON.stringify(simResult, null, 2)}
              </pre>
            </Panel>
          )}
        </div>
      </div>

      {/* -- Break-Glass Modal ---------------------------------------------- */}
      {bgModalOpen && (
        <BreakGlassModal
          onClose={() => setBgModalOpen(false)}
          onActivate={handleBreakGlassActivate}
        />
      )}
    </div>
  );
}
